!function(){"use strict";function boot(){document.querySelectorAll(".pckz-product [data-pckz-slider]").forEach(root=>{root.dataset.pckzSliderReady||(root.dataset.pckzSliderReady="1",function(root){const track=root.querySelector(".slider");if(!track)return;const prev=root.querySelector(".slider-button--prev"),next=root.querySelector(".slider-button--next"),slide=root.querySelector(".slider__slide"),step=slide?slide.offsetWidth+8:120,updateButtons=()=>{const max=track.scrollWidth-track.clientWidth-2;prev&&(prev.disabled=track.scrollLeft<=2),next&&(next.disabled=track.scrollLeft>=max)};prev&&prev.addEventListener("click",()=>{track.scrollBy({left:-step,behavior:"smooth"})}),next&&next.addEventListener("click",()=>{track.scrollBy({left:step,behavior:"smooth"})}),track.addEventListener("scroll",updateButtons,{passive:!0}),window.addEventListener("resize",updateButtons),updateButtons()}(root))})}window.pckzInitSliders=boot,"loading"===document.readyState?document.addEventListener("DOMContentLoaded",boot):boot()}();